from __future__ import annotations

import base64
import hashlib
import hmac
import os
import sys
import time

from agntspce_search.branding import env_var

HMAC_SECRET = b"agntspce-search-integration-v1-do-not-rely-on-this-for-security"

TOKEN_TTL_SECS = 86400

_EXIT_MSG_CLEAN = (
    "[agntspce-search] not activated: AGNTSPCE_SEARCH_SESSION not set or invalid.\n"
    "[agntspce-search] This server is designed to run exclusively inside AgntSpce.\n"
)


def _hmac_sha256(secret: bytes, data: bytes) -> bytes:
    return hmac.new(secret, data, hashlib.sha256).digest()


def _add_padding(s: str) -> str:
    """Add base64 padding if missing (Node.js base64url strips it)."""
    m = len(s) % 4
    return s + "=" * (4 - m) if m else s


def verify_token(token: str) -> tuple[int, int, str] | str:
    try:
        decoded = base64.urlsafe_b64decode(_add_padding(token))
    except Exception:
        return "invalid base64 encoding"

    if len(decoded) < 33:
        return "token too short"

    payload_len = len(decoded) - 32
    payload = decoded[:payload_len]
    signature = decoded[payload_len:]

    expected_sig = _hmac_sha256(HMAC_SECRET, payload)
    if not hmac.compare_digest(signature, expected_sig):
        return "invalid signature"

    try:
        payload_str = payload.decode("utf-8")
    except UnicodeDecodeError:
        return "invalid UTF-8 in token payload"

    parts = payload_str.split(":")
    if len(parts) < 2:
        return "malformed token payload"

    try:
        pid = int(parts[0])
    except ValueError:
        return "invalid PID"

    try:
        expiry = int(parts[1])
    except ValueError:
        return "invalid expiry timestamp"

    now = time.time()
    if now > expiry:
        return f"token expired (expiry={expiry}, now={int(now)})"

    nonce = parts[2] if len(parts) > 2 else ""
    return pid, expiry, nonce


def check() -> bool:
    token = os.environ.get(env_var("SESSION"), "")
    if not token:
        return False

    result = verify_token(token)
    if isinstance(result, str):
        return False

    pid, _expiry, _nonce = result

    # Tier 1: direct parent match (MCP server spawned directly by the agent)
    if pid == os.getppid():
        return True

    # Tier 2: PID still alive (the agent or AgntSpce is still running)
    try:
        os.kill(pid, 0)
        return True
    except OSError:
        return False


# Exit code 77 = EX_NOPERM (sysexits.h): permission denied.
# Distinct from exit 0 (search returned results/no-results) and exit 1 (generic error).
_EXIT_DENIED = 77


def enforce() -> None:
    if check():
        return

    token = os.environ.get(env_var("SESSION"), "")
    if not token:
        print(_EXIT_MSG_CLEAN.strip(), file=sys.stderr)
        sys.exit(_EXIT_DENIED)

    result = verify_token(token)
    if isinstance(result, str):
        print(f"[agntspce-search] activation rejected: {result}", file=sys.stderr)
        sys.exit(_EXIT_DENIED)

    pid, _expiry, _nonce = result
    if pid != os.getppid():
        detail = f"PID mismatch: token PID={pid}, parent PID={os.getppid()}"
    else:
        detail = "PID not alive"
    print(f"[agntspce-search] activation rejected: {detail}", file=sys.stderr)
    sys.exit(_EXIT_DENIED)
